vec2 rotateAround(vec2 uv, vec2 center, float angle, float aspect) {
  vec2 p = (uv - center) * vec2(aspect, 1.0);
  float c = cos(angle);
  float s = sin(angle);
  p = mat2(c, -s, s, c) * p;
  return p / vec2(aspect, 1.0) + center;
}

vec3 getRayDirection(vec2 uv, float aspect, float focalLength) {
  vec2 screen = vec2((uv.x - uPos.x) * aspect, uv.y - uPos.y);
  return normalize(vec3(screen, focalLength));
