bool intersectAABB(vec3 rayOrigin, vec3 rayDir, vec3 boxMin, vec3 boxMax) {
  vec3 safeRayDir = vec3(
    abs(rayDir.x) < EPSILON ? (rayDir.x < 0.0 ? -EPSILON : EPSILON) : rayDir.x,
    abs(rayDir.y) < EPSILON ? (rayDir.y < 0.0 ? -EPSILON : EPSILON) : rayDir.y,
    abs(rayDir.z) < EPSILON ? (rayDir.z < 0.0 ? -EPSILON : EPSILON) : rayDir.z
  );
  vec3 t0 = (boxMin - rayOrigin) / safeRayDir;
  vec3 t1 = (boxMax - rayOrigin) / safeRayDir;
  vec3 tMin3 = min(t0, t1);
  vec3 tMax3 = max(t0, t1);
  float tMin = max(max(tMin3.x, tMin3.y), max(tMin3.z, 0.0));
  float tMax = min(min(tMax3.x, tMax3.y), tMax3.z);
  return tMax >= tMin;
}

bool intersectSidePlane(vec3 rayOrigin, vec3 rayDir, float planeOffset, vec2 planeCenter, vec2 planeHalfSize, bool planeIsY, out float tHit, out vec2 hitLocal) {
  float rayAxis = planeIsY ? rayDir.y : rayDir.x;
  float originAxis = planeIsY ? rayOrigin.y : rayOrigin.x;
  float safeRayAxis = sign(rayAxis) * max(abs(rayAxis), EPSILON);
  tHit = (planeOffset - originAxis) / safeRayAxis;

  if (tHit <= 0.0) {
    return false;
  }

  vec3 hit = rayOrigin + rayDir * tHit;
  hitLocal = planeIsY
    ? vec2(hit.x - planeCenter.x, hit.z - planeCenter.y)
    : vec2(hit.y - planeCenter.x, hit.z - planeCenter.y);

  if (abs(hitLocal.x) > planeHalfSize.x || abs(hitLocal.y) > planeHalfSize.y) {
    return false;
  }

  return true;
}

