vec4 renderFlatBlocks(vec2 uv, vec4 baseColor, float aspect, float time) {
  vec4 color = baseColor;
  int blockCount = clamp(uDensity, 1, MAX_BLOCKS);
  float countRange = max(float(blockCount - 1), 1.0);
  float baseSize = mix(0.01, 0.07, uSize);
  float spread = mix(0.25, 1.25, uSpread);
  float blurStrength = mix(0.0025, 0.03, uDepthBlur);
  float skewAspect = exp2((uSkew - 0.5) * 2.4);
  vec2 flatStretch = vec2(1.95, 0.85);
  float maxSizeVariance = mix(1.0, 1.9, uVariance);
  float maxAspectVariance = mix(1.0, 1.6, uVariance);
  float maxDepthScale = 1.35;
  float skewBound = max(skewAspect, 1.0 / skewAspect);
  vec2 maxHalfSize = baseSize * maxSizeVariance * maxDepthScale * flatStretch * skewBound * maxAspectVariance;
  vec2 bandReach = vec2(
    spread * 0.5 + maxHalfSize.x + blurStrength / aspect,
    spread * 0.5 + maxHalfSize.y + blurStrength
  );
  float travelMargin = max(
    maxHalfSize.x + blurStrength / aspect,
    0.16
  );
  float crossAxisDistance = abs(uv.y - uPos.y);
  float crossAxisBand = bandReach.y;
  float remainingAlpha = 1.0;

  if (crossAxisDistance > crossAxisBand) {
    return color;
  }

  for (int i = 0; i < MAX_BLOCKS; i++) {
    if (i >= blockCount) {
      break;
    }

    float fi = float(i) + 1.0;
    vec2 rnd = hash21(fi * 23.17);
    float rnd2 = fract((rnd.x + rnd.y) * 12.35731);
    float rnd3 = fract((rnd.x * 5.731 + rnd.y * 9.137) * 4.17321);
    float layerDepth = clamp((float(i) + rnd.x * 0.75) / (countRange + 0.75), 0.0, 1.0);
    float travel = fract(rnd.y + time * mix(0.18, 1.0, layerDepth));
    float sizeVariance = mix(1.0, mix(0.55, 1.9, rnd2), uVariance);
    float aspectVariance = mix(1.0, mix(0.65, 1.6, rnd3), uVariance);
    float depthScale = mix(0.6, 1.35, layerDepth);
    vec2 stretch = flatStretch;

    stretch *= vec2(skewAspect, 1.0 / skewAspect);
    stretch *= vec2(aspectVariance, 1.0 / aspectVariance);

    vec2 center = vec2(
      mix(-travelMargin, 1.0 + travelMargin, travel),
      uPos.y + (rnd.x - 0.5) * spread
    );

    vec2 halfSize = baseSize * sizeVariance * depthScale * stretch;
    vec2 local = vec2((uv.x - center.x) * aspect, uv.y - center.y);
    vec2 boxHalfSize = vec2(halfSize.x * aspect, halfSize.y);
    float feather = blurStrength * mix(1.0, 0.16, layerDepth);

    if (abs(local.x) > boxHalfSize.x + feather || abs(local.y) > boxHalfSize.y + feather) {
      continue;
    }

    float box = 0.0;
    if (uAiShape >= 2.0) {
      box = length(local) - boxHalfSize.x;
    } else if (uAiShape >= 1.0) {
      vec2 q = abs(local) - (boxHalfSize - boxHalfSize.x);
      box = length(max(q, 0.0)) + min(max(q.x, q.y), 0.0) - boxHalfSize.x;
    } else {
      box = sdBox(local, boxHalfSize);
    }
    float mask = 1.0 - smoothstep(0.0, feather, box);
    float alphaDepth = layerDepth * (1.35 - 0.35 * layerDepth);
    float alpha = mask * mix(0.16, 0.88, alphaDepth);
    vec3 blockColor = mix(uColor1, uColor2, rnd2);
    blockColor *= mix(0.72, 1.08, layerDepth);
    vec3 blendedColor = getBlockBlend(blockColor, color.rgb);
    color = vec4(mix(color.rgb, blendedColor, alpha), max(color.a, alpha));
    remainingAlpha *= 1.0 - alpha;

    if (remainingAlpha < 0.015) {
