const int MAX_BLOCKS = 60;
const float EPSILON = 0.0001;
const float PI = 3.14159265359;
const float TAU = 6.28318530718;

vec2 hash21(float n) {
  return fract(sin(vec2(n, n + 17.0) * vec2(127.1, 311.7)) * 43758.5453123);
}

float sdBox(vec2 p, vec2 b) {
  vec2 d = abs(p) - b;
  return length(max(d, 0.0)) + min(max(d.x, d.y), 0.0);
}

vec2 rotateAround(vec2 uv, vec2 center, float angle, float aspect) {
  vec2 p = (uv - center) * vec2(aspect, 1.0);
  float c = cos(angle);
  float s = sin(angle);
  p = mat2(c, -s, s, c) * p;
  return p / vec2(aspect, 1.0) + center;
}

vec3 getRayDirection(vec2 uv, float aspect, float focalLength) {
  vec2 screen = vec2((uv.x - uPos.x) * aspect, uv.y - uPos.y);
  return normalize(vec3(screen, focalLength));
}

bool intersectAABB(vec3 rayOrigin, vec3 rayDir, vec3 boxMin, vec3 boxMax) {
  vec3 safeRayDir = vec3(
    abs(rayDir.x) < EPSILON ? (rayDir.x < 0.0 ? -EPSILON : EPSILON) : rayDir.x,
    abs(rayDir.y) < EPSILON ? (rayDir.y < 0.0 ? -EPSILON : EPSILON) : rayDir.y,
    abs(rayDir.z) < EPSILON ? (rayDir.z < 0.0 ? -EPSILON : EPSILON) : rayDir.z
  );
  vec3 t0 = (boxMin - rayOrigin) / safeRayDir;
  vec3 t1 = (boxMax - rayOrigin) / safeRayDir;
  vec3 tMin3 = min(t0, t1);
  vec3 tMax3 = max(t0, t1);
  float tMin = max(max(tMin3.x, tMin3.y), max(tMin3.z, 0.0));
  float tMax = min(min(tMax3.x, tMax3.y), tMax3.z);
  return tMax >= tMin;
}

bool intersectSidePlane(vec3 rayOrigin, vec3 rayDir, float planeOffset, vec2 planeCenter, vec2 planeHalfSize, bool planeIsY, out float tHit, out vec2 hitLocal) {
  float rayAxis = planeIsY ? rayDir.y : rayDir.x;
  float originAxis = planeIsY ? rayOrigin.y : rayOrigin.x;
  float safeRayAxis = sign(rayAxis) * max(abs(rayAxis), EPSILON);
  tHit = (planeOffset - originAxis) / safeRayAxis;

  if (tHit <= 0.0) {
    return false;
  }

  vec3 hit = rayOrigin + rayDir * tHit;
  hitLocal = planeIsY
    ? vec2(hit.x - planeCenter.x, hit.z - planeCenter.y)
    : vec2(hit.y - planeCenter.x, hit.z - planeCenter.y);

  if (abs(hitLocal.x) > planeHalfSize.x || abs(hitLocal.y) > planeHalfSize.y) {
    return false;
  }

  return true;
}

vec3 getBlockBlend(vec3 blockColor, vec3 baseColor) {
  // #ifelseopen
  if (uBlendMode > 0) {
    return blend(uBlendMode, blockColor, baseColor);
  }
  // #ifelseclose

  return blockColor;
}

float angleDelta(float a, float b) {
  return mod(a - b + PI, TAU) - PI;
}

float sdArcSegment(float radiusNow, float angleNow, float radius, float angleCenter, vec2 halfSize) {
  float tangentDistance = angleDelta(angleNow, angleCenter) * max(radius, EPSILON);
  return sdBox(vec2(radiusNow - radius, tangentDistance), halfSize);
}

vec4 getBlendedColor(vec4 color, vec3 blockColor, float alpha) {
  return vec4(
    mix(color.rgb, getBlockBlend(blockColor, color.rgb), alpha),
    max(color.a, alpha)
  );
}

vec4 renderFlatBlocks(vec2 uv, vec4 baseColor, float aspect, float time) {
  vec4 color = baseColor;
  int blockCount = clamp(uDensity, 1, MAX_BLOCKS);
  float countRange = max(float(blockCount - 1), 1.0);
  float baseSize = mix(0.01, 0.07, uSize);
  float spread = mix(0.25, 1.25, uSpread);
  float blurStrength = mix(0.0025, 0.03, uDepthBlur);
  float skewAspect = exp2((uSkew - 0.5) * 2.4);
  vec2 flatStretch = vec2(1.95, 0.85);
  float maxSizeVariance = mix(1.0, 1.9, uVariance);
  float maxAspectVariance = mix(1.0, 1.6, uVariance);
  float maxDepthScale = 1.35;
  float skewBound = max(skewAspect, 1.0 / skewAspect);
  vec2 maxHalfSize = baseSize * maxSizeVariance * maxDepthScale * flatStretch * skewBound * maxAspectVariance;
  vec2 bandReach = vec2(
    spread * 0.5 + maxHalfSize.x + blurStrength / aspect,
    spread * 0.5 + maxHalfSize.y + blurStrength
  );
  float travelMargin = max(
    maxHalfSize.x + blurStrength / aspect,
    0.16
  );
  float crossAxisDistance = abs(uv.y - uPos.y);
  float crossAxisBand = bandReach.y;
  float remainingAlpha = 1.0;

  if (crossAxisDistance > crossAxisBand) {
    return color;
  }

  for (int i = 0; i < MAX_BLOCKS; i++) {
    if (i >= blockCount) {
      break;
    }

    float fi = float(i) + 1.0;
    vec2 rnd = hash21(fi * 23.17);
    float rnd2 = fract((rnd.x + rnd.y) * 12.35731);
    float rnd3 = fract((rnd.x * 5.731 + rnd.y * 9.137) * 4.17321);
    float layerDepth = clamp((float(i) + rnd.x * 0.75) / (countRange + 0.75), 0.0, 1.0);
    float travel = fract(rnd.y + time * mix(0.18, 1.0, layerDepth));
    float sizeVariance = mix(1.0, mix(0.55, 1.9, rnd2), uVariance);
    float aspectVariance = mix(1.0, mix(0.65, 1.6, rnd3), uVariance);
    float depthScale = mix(0.6, 1.35, layerDepth);
    vec2 stretch = flatStretch;

    stretch *= vec2(skewAspect, 1.0 / skewAspect);
    stretch *= vec2(aspectVariance, 1.0 / aspectVariance);

    vec2 center = vec2(
      mix(-travelMargin, 1.0 + travelMargin, travel),
      uPos.y + (rnd.x - 0.5) * spread
    );

    vec2 halfSize = baseSize * sizeVariance * depthScale * stretch;
    vec2 local = vec2((uv.x - center.x) * aspect, uv.y - center.y);
    vec2 boxHalfSize = vec2(halfSize.x * aspect, halfSize.y);
    float feather = blurStrength * mix(1.0, 0.16, layerDepth);

    if (abs(local.x) > boxHalfSize.x + feather || abs(local.y) > boxHalfSize.y + feather) {
      continue;
    }

    float box = 0.0;
    if (uAiShape >= 2.0) {
      box = length(local) - boxHalfSize.x;
    } else if (uAiShape >= 1.0) {
      vec2 q = abs(local) - (boxHalfSize - boxHalfSize.x);
      box = length(max(q, 0.0)) + min(max(q.x, q.y), 0.0) - boxHalfSize.x;
    } else {
      box = sdBox(local, boxHalfSize);
    }
    float mask = 1.0 - smoothstep(0.0, feather, box);
    float alphaDepth = layerDepth * (1.35 - 0.35 * layerDepth);
    float alpha = mask * mix(0.16, 0.88, alphaDepth);
    vec3 blockColor = mix(uColor1, uColor2, rnd2);
    blockColor *= mix(0.72, 1.08, layerDepth);
    vec3 blendedColor = getBlockBlend(blockColor, color.rgb);
    color = vec4(mix(color.rgb, blendedColor, alpha), max(color.a, alpha));
    remainingAlpha *= 1.0 - alpha;

    if (remainingAlpha < 0.015) {
      break;
    }
  }

  return color;
}

vec4 renderCircularBlocks(vec2 uv, vec4 baseColor, float aspect, float time) {
  vec4 color = baseColor;
  int blockCount = clamp(uDensity, 1, MAX_BLOCKS);
  float countRange = max(float(blockCount - 1), 1.0);
  float baseSize = mix(0.008, 0.05, uSize);
  float ringRadius = mix(0.08, 0.55, uSpread);
  float blurStrength = mix(0.0025, 0.03, uDepthBlur);
  float skewAspect = exp2((uSkew - 0.5) * 2.4);
  vec2 circularStretch = vec2(0.45, 1.85);
  float maxSizeVariance = mix(1.0, 1.9, uVariance);
  float maxAspectVariance = mix(1.0, 1.6, uVariance);
  float maxDepthScale = 1.35;
  float skewBound = max(skewAspect, 1.0 / skewAspect);
  vec2 maxHalfSize = baseSize * maxSizeVariance * maxDepthScale * circularStretch * skewBound * maxAspectVariance;
  float radialVariance = ringRadius * 0.45 * uVariance;
  float remainingAlpha = 1.0;
  vec2 ringLocal = (uv - uPos) * vec2(aspect, 1.0);
  float ringDistance = length(ringLocal);
  float ringAngle = atan(ringLocal.y, ringLocal.x);

  if (abs(ringDistance - ringRadius) > radialVariance + maxHalfSize.x + blurStrength) {
    return color;
  }

  for (int i = 0; i < MAX_BLOCKS; i++) {
    if (i >= blockCount) {
      break;
    }

    float fi = float(i) + 1.0;
    vec2 rnd = hash21(fi * 23.17);
    float rnd2 = fract((rnd.x + rnd.y) * 12.35731);
    float rnd3 = fract((rnd.x * 5.731 + rnd.y * 9.137) * 4.17321);
    float layerDepth = clamp((float(i) + rnd.x * 0.75) / (countRange + 0.75), 0.0, 1.0);
    float travel = fract(rnd.y + time * mix(0.18, 1.0, layerDepth));
    float sizeVariance = mix(1.0, mix(0.55, 1.9, rnd2), uVariance);
    float aspectVariance = mix(1.0, mix(0.65, 1.6, rnd3), uVariance);
    float depthScale = mix(0.6, 1.35, layerDepth);
    vec2 stretch = circularStretch;

    stretch *= vec2(skewAspect, 1.0 / skewAspect);
    stretch *= vec2(aspectVariance, 1.0 / aspectVariance);

    vec2 halfSize = baseSize * sizeVariance * depthScale * stretch;
    float segmentRadius = max(ringRadius + (rnd3 - 0.5) * radialVariance, halfSize.x + blurStrength);
    float segmentAngle = travel * TAU;
    float tangentDistance = angleDelta(ringAngle, segmentAngle) * segmentRadius;
    float feather = blurStrength * mix(1.0, 0.16, layerDepth);

    if (abs(ringDistance - segmentRadius) > halfSize.x + feather || abs(tangentDistance) > halfSize.y + feather) {
      continue;
    }

    float segment = 0.0;
    if (uAiShape >= 2.0) {
      segment = length(vec2(ringDistance - segmentRadius, tangentDistance)) - halfSize.x;
    } else if (uAiShape >= 1.0) {
      vec2 q = abs(vec2(ringDistance - segmentRadius, tangentDistance)) - (halfSize - halfSize.x);
      segment = length(max(q, 0.0)) + min(max(q.x, q.y), 0.0) - halfSize.x;
    } else {
      segment = sdArcSegment(ringDistance, ringAngle, segmentRadius, segmentAngle, halfSize);
    }
    float mask = 1.0 - smoothstep(0.0, feather, segment);
    float alphaDepth = layerDepth * (1.35 - 0.35 * layerDepth);
    float alpha = mask * mix(0.16, 0.88, alphaDepth);
    vec3 blockColor = mix(uColor1, uColor2, rnd2);
    blockColor *= mix(0.72, 1.08, layerDepth);
    vec3 blendedColor = getBlockBlend(blockColor, color.rgb);
    color = vec4(mix(color.rgb, blendedColor, alpha), max(color.a, alpha));
    remainingAlpha *= 1.0 - alpha;

    if (remainingAlpha < 0.015) {
      break;
    }
  }

  return color;
}

vec4 renderPerspectiveBlocks(vec2 uv, vec4 baseColor, float aspect, float time) {
  vec4 color = baseColor;
  int blockCount = clamp(uDensity, 1, MAX_BLOCKS);
  float countRange = max(float(blockCount - 1), 1.0);
  float baseSize = mix(0.002, 0.07, uSize);
  float spread = mix(0.25, 1.25, uSpread);
  float skewAspect = exp2(((1. - uSkew) - 0.25) * 2.4) * 2.4;
  float skewBound = max(skewAspect, 1.0 / skewAspect);
