  float nearestHit = 1e9;
  float secondHit = 1e9;
  float nearestNearFactor = 0.0;
  float secondNearFactor = 0.0;
  float nearestHitDepth = 1.0;
  float secondHitDepth = 1.0;
  float nearestFarDepth = 1.0;
  float secondFarDepth = 1.0;
  float nearestRnd = 0.0;
  float secondRnd = 0.0;
  vec2 nearestLocal = vec2(0.0);
  vec2 secondLocal = vec2(0.0);
