    return color;
  }

  for (int i = 0; i < MAX_BLOCKS; i++) {
    if (i >= blockCount) {
      break;
    }

    float fi = float(i) + 1.0;
    vec2 rnd = hash21(fi * 23.17);
    float rnd2 = fract((rnd.x + rnd.y) * 12.35731);
    float rnd3 = fract((rnd.x * 5.731 + rnd.y * 9.137) * 4.17321);
    float layerDepth = clamp((float(i) + rnd.x * 0.75) / (countRange + 0.75), 0.0, 1.0);
    float travel = fract(rnd.y + time * mix(0.18, 1.0, layerDepth));
    float nearTravel = travel;
    float sizeVariance = mix(1.0, mix(0.55, 1.9, rnd2), uVariance);
    float aspectVariance = mix(1.0, mix(0.65, 1.6, rnd3), uVariance);
    float side = mix(-1.0, 1.0, step(0.5, rnd2));
    float laneOffset = side * mix(laneWidth, 2.6, rnd.x);
    float crossOffset = perspectiveCenter + (rnd3 - 0.5) * mix(0.08, 2.6, spread) * variance;
    float planeThickness = baseSize * mix(1.1, 2.6, sizeVariance);
    float planeLength = baseSize * mix(5.0, 13.0, sizeVariance) * mix(1.15, 3.2, rnd2);
    float planeOffset = laneOffset;
    vec2 planeHalfSize = vec2(planeThickness, planeLength);

    planeHalfSize *= perspectiveStretch;
    planeHalfSize *= vec2(skewAspect, 1.0 / skewAspect);
    planeHalfSize *= vec2(aspectVariance, 1.0 / aspectVariance);

    float sizeDepthBoost = planeLength * perspectiveStretch.y * 0.42;
    float farDepth = 5.4 + sizeDepthBoost * 2.5;
    float nearDepth = -planeHalfSize.y - baseSize * 2.0;
    float depth = mix(farDepth, nearDepth, nearTravel);
    vec2 planeCenter = vec2(crossOffset, depth);

// AI edit: restored shape logic
    float tHit;
    vec2 hitLocal;
    bool hit = false;
    if (uAiShape >= 2.0) {
      hit = intersectSidePlane(rayOrigin, rayDir, planeOffset, planeCenter, vec2(planeHalfSize.x), false, tHit, hitLocal);
      if (hit && length(hitLocal) > planeHalfSize.x) hit = false;
    } else if (uAiShape >= 1.0) {
      hit = intersectSidePlane(rayOrigin, rayDir, planeOffset, planeCenter, planeHalfSize, false, tHit, hitLocal);
      if (hit) {
        vec2 q = abs(hitLocal) - (planeHalfSize - planeHalfSize.x);
        if (q.y > 0.0 && length(vec2(q.x, q.y)) > planeHalfSize.x) hit = false;
      }
    } else {
      hit = intersectSidePlane(rayOrigin, rayDir, planeOffset, planeCenter, planeHalfSize, false, tHit, hitLocal);
    }

    if (hit) {
      if (tHit < nearestHit) {
        secondHit = nearestHit;
        secondNearFactor = nearestNearFactor;
        secondHitDepth = nearestHitDepth;
        secondFarDepth = nearestFarDepth;
        secondRnd = nearestRnd;
        secondLocal = nearestLocal;
        secondHalfSize = nearestHalfSize;
        hasSecondHit = hasHit;

        nearestHit = tHit;
        nearestNearFactor = nearTravel;
        nearestHitDepth = planeCenter.y + hitLocal.y;
        nearestFarDepth = farDepth;
        nearestRnd = rnd2;
        nearestLocal = hitLocal;
        nearestHalfSize = planeHalfSize;
        hasHit = true;
      } else if (tHit < secondHit) {
        secondHit = tHit;
        secondNearFactor = nearTravel;
        secondHitDepth = planeCenter.y + hitLocal.y;
        secondFarDepth = farDepth;
        secondRnd = rnd2;
        secondLocal = hitLocal;
        secondHalfSize = planeHalfSize;
        hasSecondHit = true;
      }
    }
  }

  if (hasHit) {
    if (hasSecondHit) {
      float secondFarFade = 1.0 - smoothstep(0.85, secondFarDepth, secondHitDepth);
      float secondAlphaDepth = secondNearFactor * (1.35 - 0.35 * secondNearFactor);
      float secondAlpha = secondFarFade * mix(0.3, 0.88, secondAlphaDepth);
      vec3 secondColor = mix(uColor1, uColor2, secondRnd);
      secondColor *= mix(0.66, 1.0, secondNearFactor);
      color = getBlendedColor(color, secondColor, secondAlpha);
    }

    float farFade = 1.0 - smoothstep(0.85, nearestFarDepth, nearestHitDepth);
    float alphaDepth = nearestNearFactor * (1.35 - 0.35 * nearestNearFactor);
    float alpha = farFade * mix(0.42, 1.0, alphaDepth);
    vec3 blockColor = mix(uColor1, uColor2, nearestRnd);
    blockColor *= mix(0.7, 1.1, nearestNearFactor);
    color = getBlendedColor(color, blockColor, alpha);
  }

  return color;
}

void main() {
  vec2 uv = vTextureCoord;
  vec4 color = texture(uTexture, uv);
  float aspect = uResolution.x / max(uResolution.y, EPSILON);
  vec2 rotatedUv = uv;

  // #ifelseopen
  if(uAngle != 0.0) {
    rotatedUv = rotateAround(uv, uPos, uAngle * -6.28318530718, aspect);
  }
  // #ifelseclose

  float time = uTime * 0.01;

  switch (uDirection) {
    case 1: color = renderPerspectiveBlocks(rotatedUv, color, aspect, time); break;
    case 2: color = renderCircularBlocks(rotatedUv, color, aspect, time); break;
    default: color = renderFlatBlocks(rotatedUv, color, aspect, time); break;
  }

  // #ifelseopen
  if(uIsMask == 1) {
    vec2 maskPos = mix(vec2(0), (uMousePos - 0.5), uParentTrackMouse);
    vec4 maskColor = texture(uMaskTexture, vTextureCoord - maskPos);
    color = color * (maskColor.a * maskColor.a);
  }
  // #ifelseclose

  fragColor = color;

}

